/* форма — фон секции (.bottom_form) можно задать отдельно */
.bottom_form {
  width: 100%;
  padding: 60px 20px;
  box-sizing: border-box;
  position: relative;
  overflow: hidden;
  background-image: url('imgs/form_bg.png');
      background-size: cover;
    background-position: center;
}

.form_container {
  max-width: 1200px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 28px;
}

/* Заголовок в 2 строки как в макете: 1-я жирная, 2-я обычная (::first-line) */
.form_title {
  margin: 0;
  max-width: min(100%, 32ch);
  font-size: clamp(24px, 4vw, 36px);
  line-height: 1.15;
  color: #ffffff;
  font-weight: 400;
  font-family: inherit;
  text-align: left;
}

.form_title::first-line {
  font-weight: 700;
}

.contact_form {
  display: flex;
  flex-direction: column;
  gap: 16px;
  width: 100%;
  max-width: 520px;
}

.form_group {
  width: 100%;
}

.form_input {
  width: 100%;
  padding: 16px 20px;
  border: none;
  border-radius: 8px;
  background-color: #ffffff;
  font-size: 16px;
  color: #333333;
  box-sizing: border-box;
  font-family: inherit;
  min-height: 54px;
  transition: box-shadow 0.2s ease;
}

.form_input:focus {
  outline: none;
  box-shadow: inset 0 0 0 2px rgba(255, 122, 46, 0.45);
}

.form_input::placeholder {
  color: #999999;
  font-weight: 400;
}

.phone_input_wrapper {
  display: flex;
  align-items: stretch;
  background-color: #ffffff;
  border-radius: 8px;
  overflow: hidden;
  min-height: 54px;
}

.phone_prefix {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 0 14px;
  flex-shrink: 0;
  border-right: 1px solid #e8e8e8;
}

.flag_icon {
  font-size: 20px;
  line-height: 1;
}

.country_code {
  font-size: 16px;
  font-weight: 500;
  color: #333333;
  font-family: inherit;
}

.phone_input {
  flex: 1;
  border: none;
  border-radius: 0;
  padding: 16px 16px 16px 12px;
  min-height: 54px;
  font-size: 16px;
  box-shadow: none;
}

.phone_input_wrapper .phone_input:focus {
  outline: none;
  box-shadow: none;
}

.file_upload_wrapper {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  width: 100%;
}

.file_input {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  border: 0;
}

.file_upload_label {
    display: inline-flex;
    align-items: center;
    gap: 12px;
    padding: 5px 15px;
    background-color: #ffffff1a;
    border-radius: 8px;
    cursor: pointer;
    transition: background 0.2s ease;
    flex-shrink: 0;
    min-width: 140px;
    justify-content: space-between;
    border: 1px solid #ffffff52;
}

.file_upload_label:hover {
  background-color: #3a3a3a;
}

.plus_icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  color: #ffffff;
  font-size: 22px;
  font-weight: 300;
  line-height: 1;
}

.file_upload_text {
  font-size: 16px;
  color: #ffffff;
  font-weight: 500;
  font-family: inherit;
}

.file_label_text {
  font-size: 16px;
  color: #ffffff;
  font-weight: 400;
  font-family: inherit;
  line-height: 1.3;
}

.form_footer_row {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 20px;
  margin-top: 8px;
  flex-wrap: wrap;
}

.checkbox_group {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  margin: 0;
  flex: 1 1 220px;
  min-width: 0;
}

.form_checkbox {
  width: 20px;
  height: 20px;
  margin: 2px 0 0 0;
  cursor: pointer;
  accent-color: #ff7a2e;
  flex-shrink: 0;
}

.checkbox_label {
  font-size: 13px;
  color: #ffffff;
  cursor: pointer;
  line-height: 1.45;
  font-family: inherit;
  font-weight: 400;
}

.submit_button {
  flex-shrink: 0;
  padding: 16px 36px;
  background: linear-gradient(90deg, #ff7a2e 0%, #e63b2e 100%);
  color: #ffffff;
  border: none;
  border-radius: 8px;
  font-size: 17px;
  font-weight: 700;
  cursor: pointer;
  transition: filter 0.2s ease, transform 0.15s ease;
  font-family: inherit;
}

.submit_button:hover {
  filter: brightness(1.05);
}

.submit_button:active {
  transform: scale(0.98);
}

@media (min-width: 1024px) {
  .bottom_form {
    padding: 80px 40px;
  }
}

@media (max-width: 767px) {
  .bottom_form {
    padding: 40px 15px;
  }

  .file_upload_wrapper {
    flex-direction: column;
    align-items: stretch;
    gap: 10px;
  }

  .file_upload_label {
    width: 100%;
    justify-content: space-between;
  }

  .form_footer_row {
    flex-direction: column;
    align-items: stretch;
  }

  .submit_button {
    width: 100%;
    text-align: center;
  }
}

@media (max-width: 480px) {
  .form_input {
    padding-left: 16px;
    padding-right: 16px;
  }

  .phone_input_wrapper {
    padding-left: 4px;
    padding-right: 4px;
  }

  .file_upload_label {
    padding-left: 16px;
    padding-right: 16px;
  }

  .submit_button {
    padding: 16px 24px;
    font-size: 16px;
  }
}

.bottom_form {
    display: flex;
    align-content: center;
    flex-direction: row;
    align-items: center;
    margin-bottom: -64px;
}
.form_el_img img {
    height: 100%;
    position: absolute;
    bottom: 0;
    right: 0;
}

@media (max-width: 600px) {
.checkbox_group {
    display: flex;
    align-items: flex-start;
    gap: 12px;
    margin: 0;
    flex: 1;
    min-width: 0;
}
.form_el_img{
	width: 100%;
    height: 250px;
    display: block;
    position: relative;
}
.bottom_form{
	flex-direction: column;
}
.form_el_img img {
    height: 100%;
    position: absolute;
    bottom: -40px;
    right: -1%;
    display: block;
}

}
